107			return nil, fmt.Errorf("claude help: %w", err)
108		}
109		levels := parseClaudeReasoningLevels(string(out))
110		if len(levels) == 0 {
111			return nil, fmt.Errorf("claude help did not expose --effort levels")
112		}
113		return levels, nil
114	}
115	
116	func claudeModelDiscoveryComplete(text string) bool {
117		return len(parseClaudeModels(text)) > 0
118	}
119	
120	func claudeDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
121		snapshot := DefaultClaudeModelDiscovery()
122		if source != "" {
123			snapshot.Source = source
124		}
125		if models := parseClaudeModels(text); len(models) > 0 {
126			snapshot.Models = models
127		}
128		if levels := parseClaudeReasoningLevels(text); len(levels) > 0 {
129			snapshot.ReasoningLevels = levels
130		}
131		return snapshot
132	}
133	
134	func parseClaudeModels(text string) []string {
135		text = stripANSI(strings.ReplaceAll(text, "\r\n", "\n"))
136		lower := strings.ToLower(text)
137		models := uniqueMatches(claudeFullModelPattern.FindAllString(lower, -1))
138		for _, match := range claudeFullFamilyVersionPattern.FindAllStringSubmatch(lower, -1) {
139			if len(match) > 3 {
140				models = appendUniqueString(models, match[1]+"-"+match[2]+"."+match[3])
141			}
142		}
143		for _, match := range claudeFamilyVersionPattern.FindAllStringSubmatch(lower, -1) {
144			if len(match) > 2 {
145				models = appendUniqueString(models, match[1]+"-"+strings.ReplaceAll(match[2], "-", "."))
146			}
147		}
148		for _, match := range claudeAliasPattern.FindAllStringSubmatch(lower, -1) {
149			if len(match) > 1 {
150				models = appendUniqueString(models, match[1])
151			}
152		}
153		return models
154	}
155	
156	func ResolveClaudeFamilyAlias(model string, snapshot harnesses.ModelDiscoverySnapshot) string {
157		family := strings.ToLower(strings.TrimSpace(model))
158		if family != "sonnet" && family != "opus" && family != "haiku" {
159			return model
160		}
161		if resolved := latestClaudeFamilyVersion(family, snapshot.Models); resolved != "" {
162			return resolved
163		}
164		return model
165	}
166	
167	func latestClaudeFamilyVersion(family string, models []string) string {
168		prefix := family + "-"
169		best := ""
170		var bestParts []int
171		for _, model := range models {
172			model = strings.ToLower(strings.TrimSpace(model))
173			if !strings.HasPrefix(model, prefix) {
174				continue
175			}
176			parts, ok := parseClaudeVersionParts(strings.TrimPrefix(model, prefix))
177			if !ok {
178				continue
179			}
180			if best == "" || compareVersionParts(parts, bestParts) > 0 {
181				best = model
182				bestParts = parts
183			}
184		}
185		return best
186	}
187	
188	func parseClaudeVersionParts(version string) ([]int, bool) {
189		version = strings.ReplaceAll(version, "-", ".")
190		raw := strings.Split(version, ".")
191		if len(raw) == 0 {
192			return nil, false
193		}
194		parts := make([]int, 0, len(raw))
195		for _, part := range raw {
196			if part == "" {
197				return nil, false
198			}
199			n := 0
200			for _, r := range part {
201				if r < '0' || r > '9' {
202					return nil, false
203				}
204				n = n*10 + int(r-'0')
205			}
206			parts = append(parts, n)
207		}
208		return parts, true
209	}
210	
211	func compareVersionParts(a, b []int) int {
212		n := len(a)
213		if len(b) > n {
214			n = len(b)
215		}
216		for i := 0; i < n; i++ {
217			av, bv := 0, 0
218			if i < len(a) {
219				av = a[i]
220			}
221			if i < len(b) {
222				bv = b[i]
223			}
224			if av > bv {
225				return 1
226			}
227			if av < bv {
228				return -1
229			}
230		}
231		return 0
232	}
233	
234	func parseClaudeReasoningLevels(text string) []string {
235		text = stripANSI(strings.ReplaceAll(text, "\n", " "))
236		m := claudeEffortPattern.FindStringSubmatch(text)
237		if len(m) < 2 {
238			return nil
239		}
240		parts := strings.Split(m[1], ",")
241		out := make([]string, 0, len(parts))
242		for _, part := range parts {
243			out = appendUniqueString(out, strings.TrimSpace(part))
244		}
245		return out
246	}
247	
248	func discoveryRecord(snapshot harnesses.ModelDiscoverySnapshot) cassette.DiscoveryRecord {
249		return cassette.DiscoveryRecord{
250			Source:            snapshot.Source,
251			Status:            string(ptyquota.StatusOK),
252			Models:            append([]string(nil), snapshot.Models...),
253			ReasoningLevels:   append([]string(nil), snapshot.ReasoningLevels...),
254			CapturedAt:        snapshot.CapturedAt.UTC().Format(time.RFC3339),
255			FreshnessWindow:   snapshot.FreshnessWindow,
256			StalenessBehavior: "stale model discovery evidence requires authenticated PTY refresh before capability promotion",
257			Metadata:          map[string]any{"detail": snapshot.Detail},
258		}
259	}
260	
261	func snapshotFromDiscoveryRecord(rec cassette.DiscoveryRecord) harnesses.ModelDiscoverySnapshot {
262		capturedAt, _ := time.Parse(time.RFC3339, rec.CapturedAt)
263		detail, _ := rec.Metadata["detail"].(string)
264		return harnesses.ModelDiscoverySnapshot{
265			CapturedAt:      capturedAt,
266			Models:          append([]string(nil), rec.Models...),
267			ReasoningLevels: append([]string(nil), rec.ReasoningLevels...),
268			Source:          rec.Source,
269			FreshnessWindow: rec.FreshnessWindow,
270			Detail:          detail,
271		}
272	}
273	
274	func uniqueMatches(values []string) []string {
275		out := make([]string, 0, len(values))
276		for _, value := range values {
277			out = appendUniqueString(out, value)
278		}
279		return out
280	}
281	
282	func appendUniqueString(values []string, value string) []string {
283		value = strings.TrimSpace(value)
284		if value == "" {
285			return values
286		}
287		for _, existing := range values {
288			if existing == value {
289				return values
290			}
291		}
292		return append(values, value)
293	}
