325	func stringSet(in []string) map[string]struct{} {
326		out := make(map[string]struct{}, len(in))
327		for _, s := range in {
328			out[s] = struct{}{}
329		}
330		return out
331	}
332	
333	func stringSetEqual(a, b []string) bool {
334		if len(a) != len(b) {
335			return false
336		}
337		as := stringSet(a)
338		for _, s := range b {
339			if _, ok := as[s]; !ok {
340				return false
341			}
342		}
343		return true
344	}
345	
346	func containsString(xs []string, x string) bool {
347		for _, s := range xs {
348			if s == x {
349				return true
350			}
351		}
352		return false
353	}
